<template>
  <div>
    <br />
    <button style="font-size: 23px" id="createFile" @click="createFile()">
      创建文件</button
    ><br />
    <button style="font-size: 23px" id="writeFile" @click="writeFile()">
      写入文件</button
    ><br />
    <button style="font-size: 23px" id="readFile" @click="readFile()">
      读取文件</button
    ><br />
    <button style="font-size: 23px" id="removeFile" @click="removeFile()">
      删除文件</button
    ><br />

    <textarea id="textarea"></textarea>
  </div>
</template>

<script>
export default {
  name: "localfile", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      dataProps: "",
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    createFile() {
      var type = LocalFileSystem.PERSISTENT;
      var size = 5 * 1024 * 1024;
      window.requestFileSystem(type, size, successCallback, errorCallback);

      function successCallback(fs) {
        console.log("打开的文件系统: " + fs.name);
        fs.root.getFile(
          "createFile.txt",
          { create: true, exclusive: true },
          function (fileEntry) {
            console.log("是否是个文件？" + fileEntry.isFile.toString());
            alert("文件创建成功！");
          },
          errorCallback
        );
      }

      function errorCallback(error) {
        alert("ERROR: " + error.code);
      }
    },

    writeFile() {
      var type = LocalFileSystem.PERSISTENT;
      var size = 5 * 1024 * 1024;

      window.requestFileSystem(type, size, successCallback, errorCallback);

      function successCallback(fs) {
        fs.root.getFile(
          "createFile.txt",
          { create: true },
          function (fileEntry) {
            fileEntry.createWriter(function (fileWriter) {
              fileWriter.onwriteend = function (e) {
                alert("Write completed.");
              };

              fileWriter.onerror = function (e) {
                alert("Write failed: " + e.toString());
              };

              var blob = new Blob(["this is write info"], {
                type: "text/plain",
              });
              fileWriter.write(blob);
              alert("文件写入成功！");
            }, errorCallback);
          },
          errorCallback
        );
      }

      function errorCallback(error) {
        alert("ERROR: " + error.code);
      }
    },

    readFile() {
      var type = LocalFileSystem.PERSISTENT;
      var size = 5 * 1024 * 1024;

      window.requestFileSystem(type, size, successCallback, errorCallback);

      function successCallback(fs) {
        fs.root.getFile(
          "createFile.txt",
          {},
          function (fileEntry) {
            fileEntry.file(function (file) {
              var reader = new FileReader();

              reader.onloadend = function (e) {
                var txtArea = document.getElementById("textarea");
                txtArea.value = this.result;
              };

              reader.readAsText(file);
              alert("文件读取成功！");
            }, errorCallback);
          },
          errorCallback
        );
      }

      function errorCallback(error) {
        alert("ERROR: " + error.code);
      }
    },

    removeFile() {
      var type = LocalFileSystem.PERSISTENT;
      var size = 5 * 1024 * 1024;

      window.requestFileSystem(type, size, successCallback, errorCallback);

      function successCallback(fs) {
        fs.root.getFile(
          "createFile.txt",
          { create: false },
          function (fileEntry) {
            fileEntry.remove(function () {
              alert("文件删除成功.");
            }, errorCallback);
          },
          errorCallback
        );
      }

      function errorCallback(error) {
        alert("ERROR: " + error.code);
      }
    },
  },
};
</script>
<style lang='css' scoped>
/* @import url(); 引入css类 */
</style>